// CSingleMessage::Message contains EndPoint and CMessage which contain Vec<u8>
    // and CKeyHashMap (external_body). Verus does not derive structural equality
    // from view equality for Vec or external_body types, so this determinism check
    // is not closable from r@-equality alone. Best-effort partial proof below.
    if (r1@ == self_@) && (r2@ == self_@) {
        assert(r1@ == r2@);
        match (r1, r2) {
            (CSingleMessage::Message { seqno: s1, dst: d1, m: m1 },
             CSingleMessage::Message { seqno: s2, dst: d2, m: m2 }) => {
                assert(s1 == s2);
                assert(d1.id@ == d2.id@);
                assert(m1@ == m2@);
            }
            (CSingleMessage::Ack { ack_seqno: a1 },
             CSingleMessage::Ack { ack_seqno: a2 }) => {
                assert(a1 == a2);
                assert(r1 == r2);
            }
            (CSingleMessage::InvalidMessage {}, CSingleMessage::InvalidMessage {}) => {
                assert(r1 == r2);
            }
            _ => {
                assert(false);
            }
        }
    }
